    expect(result).toEqual([[-1, 1], [0, 1], [1, 1]]);
  });
  it.todo("should keep a 2x2 block alive (still life)");
  it.todo("should kill center cell with 4 neighbors (overpopulation)");
  it.todo("should create a living cell with exactly 3 neighbors (reproduction)");
  it.todo("should handle negative coordinates");
