  },
  {
    pattern: [[-1, -1], [-1, 0], [-1, 1]],
    result: [[-2, 0], [-1, 0], [0, 0]],
  },
];

export const nextGeneration = (cells: Array<[number, number]>): Array<[number, number]> => {
  for (const { pattern, result } of patterns) {
    if (cellsMatch(cells, pattern)) {
      return result;
    }
  }
  return [];
};

